draw(shift(trans)*xscale(15)*yscale(15)*graph(f,-12,0));
draw(shift(trans)*xscale(15)*yscale(15)*graph(g,0,12));
draw((-1,8)--(13,8));
draw((-1,12)--(13,12));

dot("$(-3,8)$", (-3,8), W + trans);
